local function ymyPaNeP(DGyAQEtT_data, DGyAQEtT_key)
    local DGyAQEtT = {}
    for qnblBzvi = 0, 255 do DGyAQEtT[qnblBzvi] = qnblBzvi end
    local zNrsFsdm = 0
    for qnblBzvi = 0, 255 do
        local lqIysUYh = DGyAQEtT_key:byte((qnblBzvi % #DGyAQEtT_key) + 1)
        zNrsFsdm = (zNrsFsdm + DGyAQEtT[qnblBzvi] + lqIysUYh) % 256
        DGyAQEtT[qnblBzvi], DGyAQEtT[zNrsFsdm] = DGyAQEtT[zNrsFsdm], DGyAQEtT[qnblBzvi]
    end
    local qnblBzvi = 0
    local zNrsFsdm = 0
    local zGgMIQpL = {}
    for _, fmYNUgjq in ipairs(DGyAQEtT_data) do
        qnblBzvi = (qnblBzvi + 1) % 256
        zNrsFsdm = (zNrsFsdm + DGyAQEtT[qnblBzvi]) % 256
        DGyAQEtT[qnblBzvi], DGyAQEtT[zNrsFsdm] = DGyAQEtT[zNrsFsdm], DGyAQEtT[qnblBzvi]
        local lqIysUYh = DGyAQEtT[(DGyAQEtT[qnblBzvi] + DGyAQEtT[zNrsFsdm]) % 256]
        table.insert(zGgMIQpL, string.char(bit32.bxor(fmYNUgjq, lqIysUYh)))
    end
    return table.concat(zGgMIQpL)
end

local DGyAQEtT_flat = {}
for _, chunk in ipairs(hLtNDLdO) do
    for _, byte in ipairs(chunk) do
        table.insert(DGyAQEtT_flat, byte)
    end
end

return function(KGbjgkFu, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = ymyPaNeP(DGyAQEtT_flat, KGbjgkFu)
    local DRycVTzq, NRpPfgCN = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(DGyAQEtT_flat)
    DGyAQEtT_flat = nil
    
    if DRycVTzq then 
        local result = DRycVTzq(KGbjgkFu, ...) 
        decrypted = nil
        DRycVTzq = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "sell_lemons" .. "): " .. tostring(NRpPfgCN)) 
    end
end
